const https = require('https');


function uploadToS3(key, bucketName, url) {
  const s3Url = `${url}/${bucketName}/${key}`;
  
  return new Promise((resolve, reject)=>
    https
      .get(s3Url, (resp) => resolve())
      .on("error", (err) => console.log('err', err))
  )
}


function processImage(body){
	const {Key: key, BucketName : bucketName } = body;
	const url = 'https://<aws_endpoint>/'

  const magick = 'convert '
	+'-resize 50x50 ' // Resize to 150px x 70 px. 50x50 is for demo only.
  +`${key} ` // Input file
	+`${key}` // Output filename, the extension must match the output format.
  +' -format ' + 'png' // Output format.

  const child = require('child_process').exec(magick);

	return uploadToS3(key, bucketName, url) // Upload image to S3.
	  .then(() => {
      console.log("done");
    })
    .catch((err)=>console.log('error', err))
}



exports.handler = async (event) => {
  const promises =  event["Records"].map(record => {
    return new Promise(resolve=>processImage({
      BucketName: record["s3"]["bucket"]["name"], 
      Key : record["s3"]["object"]["key"]
    }));
  });

  await Promise.all(promises);
};